mapper.select:
SELECT CASE WHEN a.value IS NULL THEN 'null' ELSE a.value END AS value, CASE WHEN b.label IS NULL THEN CONCAT(a.label, '(0)') ELSE b.label END AS label FROM (
SELECT DISTINCT CODEID AS value, CODETEXT AS label FROM V_CLASSIFY_INFO WHERE PARCODEID = #{sjzzflCodeId}
SELECT DISTINCT CODEVALID AS value, VALTEXT AS label FROM SYNLTE.FIELDCODEVAL WHERE UPPER(CODEID) = UPPER('GACODE000404')
) a LEFT JOIN ( SELECT
CONCAT(PRIMARY_ORGANIZATION_CH, '(', COUNT(1), ')') AS label, PRIMARY_ORGANIZATION_CH AS value
CONCAT(PRIMARY_DATASOURCE_CH, '(', COUNT(1), ')') AS label, PRIMARY_DATASOURCE_CH AS value
FROM ( SELECT
j.PRIMARY_ORGANIZATION_CH
j.PRIMARY_DATASOURCE_CH
, ROW_NUMBER() OVER (PARTITION BY LOWER(TABLE_PROJECT), UPPER(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC) AS rnn FROM DP_TABLE_ORGANIZATION_ASSETS j WHERE j.STATISTICS_TIME >= DATE_SUB(date(NOW()), INTERVAL #{daysAgo} DAY) AND j.table_type IS NOT NULL ) h WHERE h.rnn = 1
GROUP BY PRIMARY_ORGANIZATION_CH
GROUP BY PRIMARY_DATASOURCE_CH
) b ON a.label COLLATE utf8mb4_unicode_ci = b.value COLLATE utf8mb4_unicode_ci ORDER BY value;

select.if:
SELECT primaryClassifyCh, CASE WHEN (primaryClassifyCh IS NULL AND secondaryClassifyCh IS NOT NULL) THEN '汇总' WHEN (primaryClassifyCh IS NOT NULL AND secondaryClassifyCh IS NULL) THEN '合计' ELSE secondaryClassifyCh END AS secondaryClassifyCh, SUM(tableAllSum) AS tableAllSum, SUM(tableAllSize) AS tableAllSize, CASE WHEN SUM(yesterdayAllSum) = '0' THEN '0' WHEN ROUND(SUM(yesterdayAllSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(yesterdayAllSum) / 10000, 2) END AS yesterdayAllSumW, CASE WHEN SUM(averageAllDailyVolume) = '0' THEN '0' WHEN ROUND(SUM(averageAllDailyVolume) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(averageAllDailyVolume) / 10000, 2) END AS averageAllDailyVolumeW, SUM(tableNumberSum) AS tableNumberSum, CASE WHEN SUM(adsSum) = '0' THEN '0' WHEN ROUND(SUM(adsSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(adsSum) / 10000, 2) END AS adsSumW, CASE WHEN SUM(odpsSum) = '0' THEN '0' WHEN ROUND(SUM(odpsSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(odpsSum) / 10000, 2) END AS odpsSumW, CASE WHEN SUM(hbaseSum) = '0' THEN '0' WHEN ROUND(SUM(hbaseSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(hbaseSum) / 10000, 2) END AS hbaseSumW, CASE WHEN SUM(hiveSum) = '0' THEN '0' WHEN ROUND(SUM(hiveSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(hiveSum) / 10000, 2) END AS hiveSumW, CASE WHEN SUM(ckSum) = '0' THEN '0' WHEN ROUND(SUM(ckSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(ckSum) / 10000, 2) END AS ckSumW, SUM(adsSize) AS adsSize, SUM(odpsSize) AS odpsSize, SUM(hbaseSize) AS hbaseSize, SUM(hiveSize) AS hiveSize, SUM(ckSize) AS ckSize, SUM(averageAllDailySize) AS averageAllDailySize, MAX(Statistics_Day) AS statisticsDay FROM ( SELECT mainClassify, IFNULL(primaryClassifyCh, '中间表') AS primaryClassifyCh, IFNULL(secondaryClassifyCh, '中间表') AS secondaryClassifyCh, tableAllSum, tableAllSize, yesterdayAllSum, averageAllDailyVolume, tableNumberSum, Statistics_Day, todayStr, adsSum, odpsSum, hbaseSum, hiveSum, ckSum, adsSize, odpsSize, hbaseSize, hiveSize, ckSize, averageAllDailySize FROM ( SELECT 'dataOrganizationClassify' AS mainClassify, PRIMARY_ORGANIZATION_CH AS primaryClassifyCh, SECONDARY_ORGANIZATION_CH AS secondaryClassifyCh, SUM(table_all_count) AS tableAllSum, TRUNCATE(SUM(table_size) / 1073741824, 2) AS tableAllSize, SUM(AVERAGE_DAILY_VOLUME) / COUNT(*) AS averageAllDailyVolume, SUM(YESTERDAY_COUNT) AS yesterdayAllSum, COUNT(*) AS tableNumberSum, DATE_FORMAT(STATISTICS_TIME, '%Y%m%d') AS Statistics_Day, DATE_FORMAT(STATISTICS_TIME, '%Y%m%d') AS todayStr, SUM(CASE WHEN UPPER(table_type) = 'ADS' THEN table_all_count ELSE 0 END) AS adsSum, SUM(CASE WHEN UPPER(table_type) = 'ODPS' THEN table_all_count ELSE 0 END) AS odpsSum, SUM(CASE WHEN UPPER(table_type) = 'HBASE' THEN table_all_count ELSE 0 END) AS hbaseSum, SUM(CASE WHEN UPPER(table_type) LIKE '%HIVE%' THEN table_all_count ELSE 0 END) AS hiveSum, SUM(CASE WHEN UPPER(table_type) = 'CLICKHOUSE' THEN table_all_count ELSE 0 END) AS ckSum, TRUNCATE(SUM(CASE WHEN UPPER(table_type) = 'ADS' THEN table_size ELSE 0 END) / 1073741824, 2) AS adsSize, TRUNCATE(SUM(CASE WHEN UPPER(table_type) = 'ODPS' THEN table_size ELSE 0 END) / 1073741824, 2) AS odpsSize, TRUNCATE(SUM(CASE WHEN UPPER(table_type) = 'HBASE' THEN table_size ELSE 0 END) / 1073741824, 2) AS hbaseSize, TRUNCATE(SUM(CASE WHEN UPPER(table_type) LIKE '%HIVE%' THEN table_size ELSE 0 END) / 1073741824, 2) AS hiveSize, TRUNCATE(SUM(CASE WHEN UPPER(table_type) = 'CLICKHOUSE' THEN table_size ELSE 0 END) / 1073741824, 2) AS ckSize, CASE WHEN (SUM(CASE WHEN AVERAGE_DAILY_SIZE IS NULL THEN 0 ELSE AVERAGE_DAILY_SIZE END) / COUNT(*)) IS NULL THEN 0 WHEN (SUM(CASE WHEN AVERAGE_DAILY_SIZE IS NULL THEN 0 ELSE AVERAGE_DAILY_SIZE END) / COUNT(*)) / 1073741824 > 0 AND (SUM(CASE WHEN AVERAGE_DAILY_SIZE IS NULL THEN 0 ELSE AVERAGE_DAILY_SIZE END) / COUNT(*)) / 1073741824 < 0.01 THEN 0.01 ELSE TRUNCATE((SUM(CASE WHEN AVERAGE_DAILY_SIZE IS NULL THEN 0 ELSE AVERAGE_DAILY_SIZE END) / COUNT(*)) / 1073741824, 2) END AS averageAllDailySize FROM ( SELECT * FROM ( SELECT j.*, ROW_NUMBER() OVER (PARTITION BY LOWER(TABLE_PROJECT), UPPER(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC) AS rnn FROM DP_TABLE_ORGANIZATION_ASSETS j WHERE STATISTICS_TIME >= DATE_SUB(date(NOW()), INTERVAL #{daysAgo} DAY) AND PRIMARY_ORGANIZATION_CH != '中间表' AND SECONDARY_ORGANIZATION_CH != '中间表' ) h
h.rnn = 1
) t11
PRIMARY_ORGANIZATION_CH = #{primaryClassifyCh}
AND SECONDARY_ORGANIZATION_CH = #{secondaryClassifyCh}
AND THREELEVEL_ORGANIZATION_CH = #{threeValue}
AND (PRIMARY_ORGANIZATION_CH IS NULL OR PRIMARY_ORGANIZATION_CH = '中间表')
AND (SECONDARY_ORGANIZATION_CH IS NULL OR SECONDARY_ORGANIZATION_CH = '中间表')
GROUP BY PRIMARY_ORGANIZATION_CH, SECONDARY_ORGANIZATION_CH, DATE_FORMAT(STATISTICS_TIME, '%Y%m%d') ) t12 ) t13 GROUP BY ROLLUP(primaryClassifyCh, secondaryClassifyCh, Statistics_Day) HAVING CONCAT(primaryClassifyCh, secondaryClassifyCh) != '中间表' AND primaryClassifyCh IS NOT NULL AND ( CASE WHEN (primaryClassifyCh IS NULL AND secondaryClassifyCh IS NOT NULL) THEN '汇总' WHEN (primaryClassifyCh IS NOT NULL AND secondaryClassifyCh IS NULL) THEN '合计' ELSE secondaryClassifyCh END IS NOT NULL )
AND (primaryClassifyCh IS NULL AND secondaryClassifyCh IS NOT NULL)

SELECT primaryClassifyCh, CASE WHEN (primaryClassifyCh IS NULL AND secondaryClassifyCh IS NOT NULL) THEN '汇总' WHEN (primaryClassifyCh IS NOT NULL AND secondaryClassifyCh IS NULL) THEN '合计' ELSE secondaryClassifyCh END AS secondaryClassifyCh, SUM(tableAllSum) AS tableAllSum, SUM(tableAllSize) AS tableAllSize, CASE WHEN SUM(yesterdayAllSum) = '0' THEN '0' WHEN ROUND(SUM(yesterdayAllSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(yesterdayAllSum) / 10000, 2) END AS yesterdayAllSumW, CASE WHEN SUM(averageAllDailyVolume) = '0' THEN '0' WHEN ROUND(SUM(averageAllDailyVolume) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(averageAllDailyVolume) / 10000, 2) END AS averageAllDailyVolumeW, SUM(tableNumberSum) AS tableNumberSum, CASE WHEN SUM(adsSum) = '0' THEN '0' WHEN ROUND(SUM(adsSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(adsSum) / 10000, 2) END AS adsSumW, CASE WHEN SUM(odpsSum) = '0' THEN '0' WHEN ROUND(SUM(odpsSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(odpsSum) / 10000, 2) END AS odpsSumW, CASE WHEN SUM(hbaseSum) = '0' THEN '0' WHEN ROUND(SUM(hbaseSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(hbaseSum) / 10000, 2) END AS hbaseSumW, CASE WHEN SUM(hiveSum) = '0' THEN '0' WHEN ROUND(SUM(hiveSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(hiveSum) / 10000, 2) END AS hiveSumW, CASE WHEN SUM(ckSum) = '0' THEN '0' WHEN ROUND(SUM(ckSum) / 10000, 2) = '0.00' THEN '0' ELSE ROUND(SUM(ckSum) / 10000, 2) END AS ckSumW, SUM(adsSize) AS adsSize, SUM(odpsSize) AS odpsSize, SUM(hbaseSize) AS hbaseSize, SUM(hiveSize) AS hiveSize, SUM(ckSize) AS ckSize, SUM(averageAllDailySize) AS averageAllDailySize, MAX(Statistics_Day) AS statisticsDay FROM ( SELECT mainClassify, IFNULL(primaryClassifyCh, '中间表') AS primaryClassifyCh, IFNULL(secondaryClassifyCh, '中间表') AS secondaryClassifyCh, tableAllSum, tableAllSize, yesterdayAllSum, averageAllDailyVolume, tableNumberSum, Statistics_Day, todayStr, adsSum, odpsSum, hbaseSum, hiveSum, ckSum, adsSize, odpsSize, hbaseSize, hiveSize, ckSize, averageAllDailySize FROM ( SELECT 'dataSourceClassify' AS mainClassify, PRIMARY_DATASOURCE_CH AS primaryClassifyCh, SECONDARY_DATASOURCE_CH AS secondaryClassifyCh, SUM(table_all_count) AS tableAllSum, TRUNCATE(SUM(table_size) / 1073741824, 2) AS tableAllSize, SUM(AVERAGE_DAILY_VOLUME) / COUNT(*) AS averageAllDailyVolume, SUM(YESTERDAY_COUNT) AS yesterdayAllSum, COUNT(*) AS tableNumberSum, DATE_FORMAT(STATISTICS_TIME, '%Y%m%d') AS Statistics_Day, DATE_FORMAT(STATISTICS_TIME, '%Y%m%d') AS todayStr, SUM(CASE WHEN UPPER(table_type) = 'ADS' THEN table_all_count ELSE 0 END) AS adsSum, SUM(CASE WHEN UPPER(table_type) = 'ODPS' THEN table_all_count ELSE 0 END) AS odpsSum, SUM(CASE WHEN UPPER(table_type) = 'HBASE' THEN table_all_count ELSE 0 END) AS hbaseSum, SUM(CASE WHEN UPPER(table_type) LIKE '%HIVE%' THEN table_all_count ELSE 0 END) AS hiveSum, SUM(CASE WHEN UPPER(table_type) = 'CLICKHOUSE' THEN table_all_count ELSE 0 END) AS ckSum, TRUNCATE(SUM(CASE WHEN UPPER(table_type) = 'ADS' THEN table_size ELSE 0 END) / 1073741824, 2) AS adsSize, TRUNCATE(SUM(CASE WHEN UPPER(table_type) = 'ODPS' THEN table_size ELSE 0 END) / 1073741824, 2) AS odpsSize, TRUNCATE(SUM(CASE WHEN UPPER(table_type) = 'HBASE' THEN table_size ELSE 0 END) / 1073741824, 2) AS hbaseSize, TRUNCATE(SUM(CASE WHEN UPPER(table_type) LIKE '%HIVE%' THEN table_size ELSE 0 END) / 1073741824, 2) AS hiveSize, TRUNCATE(SUM(CASE WHEN UPPER(table_type) = 'CLICKHOUSE' THEN table_size ELSE 0 END) / 1073741824, 2) AS ckSize, CASE WHEN (SUM(CASE WHEN AVERAGE_DAILY_SIZE IS NULL THEN 0 ELSE AVERAGE_DAILY_SIZE END) / COUNT(*)) IS NULL THEN 0 WHEN (SUM(CASE WHEN AVERAGE_DAILY_SIZE IS NULL THEN 0 ELSE AVERAGE_DAILY_SIZE END) / COUNT(*)) / 1073741824 > 0 AND (SUM(CASE WHEN AVERAGE_DAILY_SIZE IS NULL THEN 0 ELSE AVERAGE_DAILY_SIZE END) / COUNT(*)) / 1073741824 < 0.01 THEN 0.01 ELSE TRUNCATE((SUM(CASE WHEN AVERAGE_DAILY_SIZE IS NULL THEN 0 ELSE AVERAGE_DAILY_SIZE END) / COUNT(*)) / 1073741824, 2) END AS averageAllDailySize FROM ( SELECT * FROM ( SELECT j.*, ROW_NUMBER() OVER (PARTITION BY LOWER(TABLE_PROJECT), UPPER(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC) AS rnn FROM DP_TABLE_ORGANIZATION_ASSETS j WHERE STATISTICS_TIME >= DATE_SUB(date(NOW()), INTERVAL #{daysAgo} DAY) AND PRIMARY_DATASOURCE_CH != '中间表' AND SECONDARY_DATASOURCE_CH != '中间表' ) h
h.rnn = 1
) t11
PRIMARY_DATASOURCE_CH = #{primaryClassifyCh}
AND SECONDARY_DATASOURCE_CH = #{secondaryClassifyCh}
AND (PRIMARY_DATASOURCE_CH IS NULL OR PRIMARY_DATASOURCE_CH = '中间表')
AND (SECONDARY_DATASOURCE_CH IS NULL OR SECONDARY_DATASOURCE_CH = '中间表')
GROUP BY PRIMARY_DATASOURCE_CH, SECONDARY_DATASOURCE_CH, DATE_FORMAT(STATISTICS_TIME, '%Y%m%d') ) t12 ) t13 GROUP BY ROLLUP(primaryClassifyCh, secondaryClassifyCh, Statistics_Day) HAVING CONCAT(primaryClassifyCh, secondaryClassifyCh) != '中间表' AND primaryClassifyCh IS NOT NULL AND ( CASE WHEN (primaryClassifyCh IS NULL AND secondaryClassifyCh IS NOT NULL) THEN '汇总' WHEN (primaryClassifyCh IS NOT NULL AND secondaryClassifyCh IS NULL) THEN '合计' ELSE secondaryClassifyCh END IS NOT NULL )
AND (primaryClassifyCh IS NULL AND secondaryClassifyCh IS NOT NULL)

mapper.select:
SELECT primaryDataSourceCh, secondaryDataSourceCh, primaryOrganizationCh, secondaryOrganizationCh, tableType, tableProject, name, tableNameEn, tableAllCount, averageDailyVolume, yesterdayCount, lifeCycle, valueRate, nullRate, tableState, statisticsTimeStr, updateType, frequency, liveType, tableid, registerState, objectId, tableSize, objectState, updateDate, updatePeriod, '' AS productStage, organizationClassifyCh, dataSourceClassifyCh, exceptionMessage, lifeCycleStatus, resourceId, isStandard FROM ( SELECT PRIMARY_DATASOURCE_CH AS primaryDataSourceCh, SECONDARY_DATASOURCE_CH AS secondaryDataSourceCh, PRIMARY_ORGANIZATION_CH AS primaryOrganizationCh, SECONDARY_ORGANIZATION_CH AS secondaryOrganizationCh, CASE WHEN (SECONDARY_ORGANIZATION_CH IS NULL OR SECONDARY_ORGANIZATION_CH = '') AND (THREELEVEL_ORGANIZATION_CH IS NULL OR THREELEVEL_ORGANIZATION_CH = '') THEN PRIMARY_ORGANIZATION_CH WHEN THREELEVEL_ORGANIZATION_CH IS NOT NULL OR THREELEVEL_ORGANIZATION_CH != '' THEN CONCAT(PRIMARY_ORGANIZATION_CH, '->', THREELEVEL_ORGANIZATION_CH) ELSE CONCAT(PRIMARY_ORGANIZATION_CH, '->', SECONDARY_ORGANIZATION_CH) END AS organizationClassifyCh, CASE WHEN SECONDARY_DATASOURCE_CH IS NULL OR SECONDARY_DATASOURCE_CH = '' THEN PRIMARY_DATASOURCE_CH ELSE CONCAT(PRIMARY_DATASOURCE_CH, '->', SECONDARY_DATASOURCE_CH) END AS dataSourceClassifyCh, CASE WHEN RES_NAME IS NULL OR RES_NAME = '' THEN CONCAT(TABLE_TYPE, '->', TABLE_PROJECT) ELSE CONCAT(TABLE_TYPE, '->', RES_NAME, '->', TABLE_PROJECT) END AS tableProject, NAME AS name, TABLE_NAME_EN AS tableNameEn, CASE WHEN TABLE_ALL_COUNT = '0' THEN '0' WHEN FORMAT(TABLE_ALL_COUNT / 10000, 2) = '0.00' THEN '0' ELSE FORMAT(TABLE_ALL_COUNT / 10000, 2) END AS tableAllCount, AVERAGE_DAILY_VOLUME AS averageDailyVolume, CASE WHEN YESTERDAY_COUNT = '0' THEN '0' WHEN FORMAT(YESTERDAY_COUNT / 10000, 2) = '0.00' THEN '0' ELSE FORMAT(YESTERDAY_COUNT / 10000, 2) END AS yesterdayCount, TABLE_TYPE AS tableType, LIFE_CYCLE AS lifeCycle, VALUE_RATE AS valueRate, NULL_RATE AS nullRate, TABLE_STATE AS tableState, OBJECT_STATE AS objectState, CASE WHEN PARTITION_MESSAGE = 0 THEN '增量' WHEN PARTITION_MESSAGE = 1 THEN '全量' ELSE '其它' END AS updateType, DATE_FORMAT(STATISTICS_TIME, '%Y-%m-%d %H:%i:%s') AS statisticsTimeStr, FREQUENCY AS frequency, LIVETYPE AS liveType, SJXJBM AS tableid, REGISTER_STATE AS registerState, OBJECT_ID AS objectId, CASE WHEN TABLE_SIZE = '0' THEN '0' WHEN FORMAT(TABLE_SIZE / 1073741824, 2) = '0.00' THEN '0' ELSE FORMAT(TABLE_SIZE / 1073741824, 2) END AS tableSize, update_date AS updateDate, update_period AS updatePeriod, '' AS productStage, EXCEPTION_MESSAGE AS exceptionMessage, LIFE_CYCLE_STATUS AS lifeCycleStatus, resourceid, ISSTANDARD AS isStandard FROM ( SELECT * FROM ( SELECT j.*, ROW_NUMBER() OVER (PARTITION BY LOWER(TABLE_TYPE), LOWER(TABLE_PROJECT), UPPER(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC) AS rnn FROM DP_TABLE_ORGANIZATION_ASSETS j WHERE STATISTICS_TIME >= date(CURDATE()) - INTERVAL #{daysAgo} DAY ) a ) h WHERE h.rnn = 1
AND REGISTER_STATE = '2'
AND (REGISTER_STATE != '2' OR REGISTER_STATE IS NULL)
AND (OBJECT_STATE = '1' OR OBJECT_STATE = '0')
AND (OBJECT_STATE = '-1' OR OBJECT_STATE IS NULL)
AND
(LOWER(TABLE_PROJECT) = LOWER(#{p.secondaryClassifyCh,jdbcType=VARCHAR}) AND UPPER(TABLE_TYPE) = UPPER(#{p.primaryClassifyCh,jdbcType=VARCHAR}) )
AND (
(
1=1
AND PRIMARY_DATASOURCE_CH = #{sc.primaryClassifyCh,jdbcType=VARCHAR}
AND
AND SECONDARY_DATASOURCE_CH = #{sc.secondaryClassifyCh,jdbcType=VARCHAR}
)
OR
(
1=1
