AND THREELEVEL_ORGANIZATION_CH = #{oc.threeLevelClassfyCh,jdbcType=VARCHAR}
)
)
AND (UPPER(TABLE_NAME_EN) LIKE CONCAT('%', UPPER(#{input,jdbcType=VARCHAR}),'%') OR UPPER(NAME) LIKE CONCAT('%', UPPER(#{input,jdbcType=VARCHAR}),'%') OR UPPER(SJXJBM) LIKE CONCAT('%', UPPER(#{input,jdbcType=VARCHAR}),'%'))
AND
UPPER(TABLE_NAME_EN) = UPPER(#{i,jdbcType=VARCHAR})
AND STR_TO_DATE(REPLACE(LASTDATAMODIFIEDTIME, '.', ''), '%Y-%m-%d %H:%i:%s') >= STR_TO_DATE(#{startLastModifiedTime,jdbcType=VARCHAR}, '%Y-%m-%d')
AND STR_TO_DATE(REPLACE(LASTDATAMODIFIEDTIME, '.', ''), '%Y-%m-%d %H:%i:%s') - 1 <= STR_TO_DATE(#{endLastModifiedTime,jdbcType=VARCHAR}, '%Y-%m-%d')
AND TABLE_ALL_COUNT >= #{startRecordNum}
