mapper.update:
BEGIN

    update DP_TABLE_ORGANIZATION_ASSETS set REGISTER_STATE = #{item.registerState}
    where UPPER(table_name_en) = UPPER(#{item.tableNameEn,jdbcType=VARCHAR})

        and UPPER(sjxjbm) = UPPER(#{item.tableid,jdbcType=VARCHAR})

    ;
    update DP_DATA_REGISTER
    set APPROVAL_STATUS = '1',
    APPROVAL_UPDATE_TIME = date_format(now(), '%Y-%m-%d %H:%i:%s')
    where TABLE_NAME_EN = #{item.tableNameEn,jdbcType=VARCHAR};

END;

BEGIN

    update DP_TABLE_ORGANIZATION_ASSETS set REGISTER_STATE = #{item.registerState}
    where UPPER(table_name_en) = UPPER(#{item.tableNameEn,jdbcType=VARCHAR})

        and UPPER(sjxjbm) = UPPER(#{item.tableid,jdbcType=VARCHAR})

    ;
    update DP_DATA_REGISTER
    set APPROVAL_STATUS = '4',
    APPROVAL_UPDATE_TIME = date_format(now(), '%Y-%m-%d %H:%i:%s')
    where TABLE_NAME_EN = #{item.tableNameEn,jdbcType=VARCHAR};

END;

BEGIN

    update DP_TABLE_ORGANIZATION_ASSETS set REGISTER_STATE = #{item.TYPE,jdbcType=VARCHAR}
    where UPPER(SJXJBM) = UPPER(#{item.TABLEID,jdbcType=VARCHAR});

END;

BEGIN

    update DP_TABLE_ORGANIZATION_ASSETS set OBJECT_STATE = #{state,jdbcType=VARCHAR}
    where UPPER(SJXJBM) = UPPER(#{item,jdbcType=VARCHAR})


    update SYNLTE.OBJECT set OBJECTSTATE = #{state,jdbcType=VARCHAR}
    where UPPER(TABLEID) = UPPER(#{item,jdbcType=VARCHAR})

END;

BEGIN
    insert into DP_DATA_REGISTER

        (SJXJBM,TABLE_NAME_EN,OBJECT_ID,APPROVAL_ID,APPROVAL_STATUS,APPROVAL_CREATE_TIME,
        APPROVAL_UPDATE_TIME,APPROVAL_TYPE,TABLE_PROJECT)
        values(#{item.tableId,jdbcType=VARCHAR},#{item.tableNameEn,jdbcType=VARCHAR},#{item.objectId,jdbcType=VARCHAR},
        #{item.approvalId,jdbcType=VARCHAR},#{item.approvalStatus,jdbcType=VARCHAR},date_format(now(), '%Y-%m-%d %H:%i:%s'),
        date_format(now(), '%Y-%m-%d %H:%i:%s'),#{item.approvalType,jdbcType=VARCHAR},
        #{item.tableProject,jdbcType=VARCHAR})
        on duplicate key update
        APPROVAL_ID = #{item.approvalId,jdbcType=VARCHAR},
        APPROVAL_STATUS = #{item.approvalStatus,jdbcType=VARCHAR},
        APPROVAL_UPDATE_TIME = date_format(now(), '%Y-%m-%d %H:%i:%s');

    update DP_TABLE_ORGANIZATION_ASSETS set

        REGISTER_STATE = #{item.approvalStatus,jdbcType=VARCHAR}
        where UPPER(SJXJBM) = UPPER(#{item.tableId,jdbcType=VARCHAR})


        LIFE_CYCLE_STATUS = #{item.approvalStatus,jdbcType=VARCHAR}
        where
        UPPER(TABLE_NAME_EN) = UPPER(#{item.tableNameEn,jdbcType=VARCHAR})


                and TABLE_TYPE = #{itm,jdbcType=VARCHAR}


                and TABLE_PROJECT = #{itm,jdbcType=VARCHAR}


    ;
END;

mapper.select:
select SJXJBM as tableId,TABLE_NAME_EN as tableNameEn,OBJECT_ID as objectId,APPROVAL_ID as approvalId,
APPROVAL_STATUS as approvalStatus,APPROVAL_CREATE_TIME as approvalCreateTime,APPROVAL_UPDATE_TIME as
approvalUpdateTime,TABLE_PROJECT as tableProject,APPROVAL_TYPE as approvalType
from DP_DATA_REGISTER where APPROVAL_STATUS = '2'


        and SJXJBM = #{item.tableId,jdbcType=VARCHAR}


        and TABLE_PROJECT = #{item.tableProject,jdbcType=VARCHAR}
        and TABLE_NAME_EN = #{item.tableNameEn,jdbcType=VARCHAR}

mapper.update:
BEGIN
update DP_DATA_REGISTER
set APPROVAL_STATUS = '1'
where TABLE_PROJECT = #{requestParam.tableProject,jdbcType=VARCHAR}
and TABLE_NAME_EN = #{requestParam.tableNameEn,jdbcType=VARCHAR}
and APPROVAL_TYPE = 'updateLifeCycle';
update DP_TABLE_ORGANIZATION_ASSETS
set LIFE_CYCLE_STATUS = '1',
LIFE_CYCLE = #{requestParam.value,jdbcType=VARCHAR}
where
STATISTICS_TIME >= date(now()) and
UPPER(TABLE_NAME_EN) = UPPER(#{requestParam.tableNameEn,jdbcType=VARCHAR})


        and TABLE_TYPE = #{itm,jdbcType=VARCHAR}


        and TABLE_PROJECT = #{itm,jdbcType=VARCHAR}


;
end;

BEGIN
update DP_DATA_REGISTER
set APPROVAL_STATUS = '4'
where TABLE_PROJECT = #{requestParam.tableProject,jdbcType=VARCHAR}
and TABLE_NAME_EN = #{requestParam.tableNameEn,jdbcType=VARCHAR}
and APPROVAL_TYPE = 'updateLifeCycle';
update DP_TABLE_ORGANIZATION_ASSETS set LIFE_CYCLE_STATUS = '4'
where
STATISTICS_TIME >= date(now()) and
UPPER(TABLE_NAME_EN) = UPPER(#{requestParam.tableNameEn,jdbcType=VARCHAR})


        and TABLE_TYPE = #{itm,jdbcType=VARCHAR}


        and TABLE_PROJECT = #{itm,jdbcType=VARCHAR}


;
end;

mapper.select:
select LIFE_CYCLE from ( SELECT j.*, row_number ( ) over ( PARTITION BY lower(TABLE_PROJECT), upper(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC ) as rnn from DP_TABLE_ORGANIZATION_ASSETS j where STATISTICS_TIME >= date(now()) ) h WHERE h.rnn = 1 and UPPER(TABLE_NAME_EN) = UPPER(#{requestParam.tableNameEn,jdbcType=VARCHAR})
and TABLE_TYPE = #{itm,jdbcType=VARCHAR}
and TABLE_PROJECT = #{itm,jdbcType=VARCHAR}

select detect_id from ds_detected_table
 where res_id = #{detailedTableByClassify.resourceId,jdbcType=VARCHAR}
   and project_name = #{detailedTableByClassify.tableProject,jdbcType=VARCHAR}
   and table_name_en =#{detailedTableByClassify.tableNameEn,jdbcType=VARCHAR}
